import json
from typing import Any

from playwright.sync_api import sync_playwright


URL = "https://csrankings.org/"
TARGET_INSTITUTION = "Shanghai Jiao Tong University"
FROM_YEAR = 2020
TO_YEAR = 2025
REGION = "world"
SELECTED_TOP_LEVEL_AREAS = ["ai", "vision", "mlmining", "nlp", "inforet"]


def _compute_result(page) -> dict[str, Any]:
    return page.evaluate(
        """
        ({ targetInstitution, fromYear, toYear, region, selectedAreas }) => {
          const csr = window.csr;
          if (!csr) {
            throw new Error('window.csr is unavailable');
          }

          const parentMap = window.CSRankings?.parentMap || {};
          const topLevelAreas = Object.fromEntries(selectedAreas.map((area) => [area, 1]));
          const selectedFieldMap = {};

          for (const field of csr.fields) {
            if (selectedAreas.includes(field)) {
              selectedFieldMap[field] = 1;
              continue;
            }
            const parent = parentMap[field];
            selectedFieldMap[field] = selectedAreas.includes(parent) ? 1 : 0;
          }

          const deptNames = {};
          const deptCounts = {};
          const facultyCount = {};
          const facultyAdjustedCount = {};
          const areaDeptAdjustedCount = {};
          const seenFaculty = {};

          const inRegion = (dept) => {
            if (region === 'world') {
              return true;
            }
            return csr.countryAbbrv[dept] === region || csr.countryInfo[dept] === region;
          };

          for (const record of csr.authors) {
            const dept = record.dept;
            if (!dept || !inRegion(dept)) {
              continue;
            }

            const year = Number(record.year);
            if (year < fromYear || year > toYear) {
              continue;
            }

            const area = record.area;
            if (!selectedFieldMap[area]) {
              continue;
            }

            const parentArea = parentMap[area] || area;
            const adjusted = Number(record.adjustedcount || 0);
            const count = Number(record.count || 0);
            const author = record.name;
            const deptAreaKey = `${parentArea}::${dept}`;

            areaDeptAdjustedCount[deptAreaKey] = (areaDeptAdjustedCount[deptAreaKey] || 0) + adjusted;

            if (!(author in seenFaculty)) {
              seenFaculty[author] = dept;
              if (!(dept in deptNames)) {
                deptNames[dept] = [];
                deptCounts[dept] = 0;
              }
              deptNames[dept].push(author);
              deptCounts[dept] += 1;
            }

            facultyCount[author] = (facultyCount[author] || 0) + count;
