import json
from typing import Any

from playwright.sync_api import sync_playwright


URL = "https://csrankings.org/"
TARGET_INSTITUTION = "Shanghai Jiao Tong University"
FROM_YEAR = 2020
TO_YEAR = 2025
REGION = "world"
SELECTED_TOP_LEVEL_AREAS = ["ai", "vision", "mlmining", "nlp", "inforet"]


def _compute_result(page) -> dict[str, Any]:
    return page.evaluate(
        """
        ({ targetInstitution, fromYear, toYear, region, selectedAreas }) => {
          const csr = window.csr;
          if (!csr) {
            throw new Error('window.csr is unavailable');
          }

          const parentMap = window.CSRankings?.parentMap || {};
          const topLevelAreas = Object.fromEntries(selectedAreas.map((area) => [area, 1]));
          const selectedFieldMap = {};

          for (const field of csr.fields) {
            if (selectedAreas.includes(field)) {
              selectedFieldMap[field] = 1;
              continue;
            }
            const parent = parentMap[field];
            selectedFieldMap[field] = selectedAreas.includes(parent) ? 1 : 0;
          }

          const deptNames = {};
          const deptCounts = {};
          const facultyCount = {};
          const facultyAdjustedCount = {};
          const areaDeptAdjustedCount = {};
          const seenFaculty = {};

          const inRegion = (dept) => {
            if (region === 'world') {
              return true;
            }
            return csr.countryAbbrv[dept] === region || csr.countryInfo[dept] === region;
          };

          for (const record of csr.authors) {
            const dept = record.dept;
            if (!dept || !inRegion(dept)) {
              continue;
            }

            const year = Number(record.year);
            if (year < fromYear || year > toYear) {
              continue;
            }

            const area = record.area;
            if (!selectedFieldMap[area]) {
              continue;
            }

            const parentArea = parentMap[area] || area;
            const adjusted = Number(record.adjustedcount || 0);
            const count = Number(record.count || 0);
            const author = record.name;
            const deptAreaKey = `${parentArea}::${dept}`;

            areaDeptAdjustedCount[deptAreaKey] = (areaDeptAdjustedCount[deptAreaKey] || 0) + adjusted;

            if (!(author in seenFaculty)) {
              seenFaculty[author] = dept;
              if (!(dept in deptNames)) {
                deptNames[dept] = [];
                deptCounts[dept] = 0;
              }
              deptNames[dept].push(author);
              deptCounts[dept] += 1;
            }

            facultyCount[author] = (facultyCount[author] || 0) + count;
            facultyAdjustedCount[author] = (facultyAdjustedCount[author] || 0) + adjusted;
          }

          const scores = {};
          const exponent = 1 / selectedAreas.length;
          for (const dept of Object.keys(deptNames)) {
            let product = 1;
            for (const area of selectedAreas) {
              const areaValue = areaDeptAdjustedCount[`${area}::${dept}`] || 0;
              product *= (areaValue + 1);
            }
            scores[dept] = Math.pow(product, exponent);
            scores[dept] = Math.round(scores[dept] * 10) / 10;
          }

          const ranked = Object.keys(scores)
            .sort((a, b) => {
              if (scores[b] !== scores[a]) {
                return scores[b] - scores[a];
              }
              return a < b ? -1 : a > b ? 1 : 0;
            });

          let rank = 0;
          let tiesAtRank = 1;
          let previousScore = Number.POSITIVE_INFINITY;
          const rows = [];

          for (const dept of ranked) {
            const score = scores[dept];
            if (score === 0) {
              break;
            }
            if (score !== previousScore) {
              rank += tiesAtRank;
              tiesAtRank = 1;
              previousScore = score;
            } else {
              tiesAtRank += 1;
            }
            rows.push({
              institution: dept,
              rank,
              count: score,
              faculty: deptCounts[dept] || 0,
            });
          }

          const target = rows.find((row) => row.institution === targetInstitution);
          if (!target) {
            throw new Error(`Institution not found in computed ranking: ${targetInstitution}`);
          }

          const finalUrl = `${window.location.origin}/#/fromyear/${fromYear}/toyear/${toYear}/index?${selectedAreas.join('&')}&${region}`;
          return {
            final_url: finalUrl,
            data: target,
          };
        }
        """,
        {
            "targetInstitution": TARGET_INSTITUTION,
            "fromYear": FROM_YEAR,
            "toYear": TO_YEAR,
            "region": REGION,
            "selectedAreas": SELECTED_TOP_LEVEL_AREAS,
        },
    )


def main() -> None:
    with sync_playwright() as p:
        browser = p.chromium.launch(headless=True)
        page = browser.new_page()
        page.goto(URL, wait_until="domcontentloaded")
        page.wait_for_timeout(4000)
        result = _compute_result(page)
        print(json.dumps(result, ensure_ascii=False, separators=(",", ":")))
        browser.close()


if __name__ == "__main__":
    main()
